pub fn main() { const W: usize = 150; const H: usize = 35; const HASH: char = 35 as char; const SPACE: char = 32 as char; const NEWLINE: char = 10 as char; const QUESTION: char = 63 as char; let s = r###"pub fn main() { const W: usize = 150; const H: usize = 35; const HASH: char = 35 as char; const SPACE: char = 32 as char; const NEWLINE: char = 10 as char; const QUESTION: char = 63 as char; let s = r#"?"#; let mut expanded = String::new(); for c in s.chars() { match c { QUESTION => expanded.push_str(s), HASH => expanded.push_str("\x23\x23\x23"), _ => expanded.push(c), } } let mut tokens = Vec::new(); let chars: Vec<char> = expanded.chars().collect(); let mut i = 0; while i < chars.len() { if chars[i].is_whitespace() { i += 1; } else { let mut token = String::new(); while i < chars.len() && !chars[i].is_whitespace() { token.push(chars[i]); i += 1; } tokens.push(token); } } let total_tokens = tokens.len(); let mut lines: Vec<Vec<String>> = vec![Vec::new(); H]; let mut current_token_idx = 0; for row in 0..H { let remaining_rows = H - row; let remaining_tokens = total_tokens - current_token_idx; let tokens_for_this_line = if remaining_rows == 1 { remaining_tokens } else { let mut count = 0; let mut width = 0; while current_token_idx + count < total_tokens { let t_len = tokens[current_token_idx + count].chars().count(); let space = if count == 0 { 0 } else { 1 }; if width + space + t_len > W { break; } width += space + t_len; count += 1; let tokens_left = total_tokens - (current_token_idx + count); if tokens_left < (remaining_rows - 1) { break; } } count.max(1) }; for _ in 0..tokens_for_this_line { if current_token_idx < total_tokens { lines[row].push(tokens[current_token_idx].clone()); current_token_idx += 1; } } } let mut final_output = String::new(); for row in 0..H { let line_tokens = &lines[row]; let mut line_str = String::new(); if line_tokens.is_empty() { line_str.push_str(&SPACE.to_string().repeat(W)); } else { let content_len: usize = line_tokens.iter().map(|t| t.chars().count()).sum(); let total_spaces_needed = W - content_len; let gaps = if line_tokens.len() > 1 { line_tokens.len() - 1 } else { 0 }; if gaps > 0 { let mut distributed = 0; for (idx, t) in line_tokens.iter().enumerate() { line_str.push_str(t); if idx < gaps { let target = (total_spaces_needed * (idx + 1)) / gaps; let count = target - distributed; line_str.push_str(&SPACE.to_string().repeat(count)); distributed += count; } } } else { line_str.push_str(&line_tokens[0]); while line_str.chars().count() < W { line_str.push(SPACE); } } } final_output.push_str(&line_str.chars().take(W).collect::<String>()); if row < H - 1 { final_output.push(NEWLINE); } } print!("{}", final_output); }"###; let mut expanded = String::new(); for c in s.chars() { match c { QUESTION => expanded.push_str(s), HASH => expanded.push_str("\x23\x23\x23"), _ => expanded.push(c), } } let mut tokens = Vec::new(); let chars: Vec<char> = expanded.chars().collect(); let mut i = 0; while i < chars.len() { if chars[i].is_whitespace() { i += 1; } else { let mut token = String::new(); while i < chars.len() && !chars[i].is_whitespace() { token.push(chars[i]); i += 1; } tokens.push(token); } } let total_tokens = tokens.len(); let mut lines: Vec<Vec<String>> = vec![Vec::new(); H]; let mut current_token_idx = 0; for row in 0..H { let remaining_rows = H - row; let remaining_tokens = total_tokens - current_token_idx; let tokens_for_this_line = if remaining_rows == 1 { remaining_tokens } else { let mut count = 0; let mut width = 0; while current_token_idx + count < total_tokens { let t_len = tokens[current_token_idx + count].chars().count(); let space = if count == 0 { 0 } else { 1 }; if width + space + t_len > W { break; } width += space + t_len; count += 1; let tokens_left = total_tokens - (current_token_idx + count); if tokens_left < (remaining_rows - 1) { break; } } count.max(1) }; for _ in 0..tokens_for_this_line { if current_token_idx < total_tokens { lines[row].push(tokens[current_token_idx].clone()); current_token_idx += 1; } } } let mut final_output = String::new(); for row in 0..H { let line_tokens = &lines[row]; let mut line_str = String::new(); if line_tokens.is_empty() { line_str.push_str(&SPACE.to_string().repeat(W)); } else { let content_len: usize = line_tokens.iter().map(|t| t.chars().count()).sum(); let total_spaces_needed = W - content_len; let gaps = if line_tokens.len() > 1 { line_tokens.len() - 1 } else { 0 }; if gaps > 0 { let mut distributed = 0; for (idx, t) in line_tokens.iter().enumerate() { line_str.push_str(t); if idx < gaps { let target = (total_spaces_needed * (idx + 1)) / gaps; let count = target - distributed; line_str.push_str(&SPACE.to_string().repeat(count)); distributed += count; } } } else { line_str.push_str(&line_tokens[0]); while line_str.chars().count() < W { line_str.push(SPACE); } } } final_output.push_str(&line_str.chars().take(W).collect::<String>()); if row < H - 1 { final_output.push(NEWLINE); } } print!("{}", final_output); }